#ifndef JRCarControlDefine_h
#define JRCarControlDefine_h

typedef NS_ENUM(NSInteger, JRCarControlIndex) {
    JRCarControlIndexLock = 0,//上锁（下电）
    JRCarControlIndexUnlock,//解锁
    JRCarControlIndexTemporaryLock,//临时上锁（不下电）
    JRCarControlIndexTrunk,//后备箱
    JRCarControlIndexWindow,//车窗
    JRCarControlIndexSkySunShade,//天窗遮阳帘
    JRCarControlIndexBehindSunShade,//天窗遮阳帘
    JRCarControlIndexFastConnector,//快充口
    JRCarControlIndexSlowConnector,//慢充口
    JRCarControlIndexQuickWarm,//极速升温
    JRCarControlIndexQuickCool,//急速降温

    JRCarControlIndexE28sMainOpen,//剪刀门主门开
    JRCarControlIndexE28sMainClose,//剪刀门主门关
    JRCarControlIndexE28sSubOpen,//剪刀门副门开
    JRCarControlIndexE28sSubClose,//剪刀门副门关

    JRCarControlIndexLeftSlideOpen,//左侧滑门开
    JRCarControlIndexLeftSlideClose,//左侧滑门关
    JRCarControlIndexRightSlideOpen,//右侧滑门开
    JRCarControlIndexRightSlideClose,//右侧滑门关
};

#endif /* JRCarControlDefine_h */

