//

#ifndef JRCarControlCellProtocol_h
#define JRCarControlCellProtocol_h

@protocol JRCarControlCellDelegate <NSObject>

@optional
- (void)sendLockDoorCommandWithIsLock:(BOOL)isLock;
- (void)sendOpenWindowCommand;
- (void)sendCloseWindowCommand;
- (void)sendSkySunShadeCommandWithIsOpen:(BOOL)isOpen; // 天窗遮阳帘操作
- (void)sendBehindSunShadeCommandWithIsOpen:(BOOL)isOpen; // 后遮阳帘操作
- (void)sendUnlockTrunkCommand;
- (void)sendLockTrunkCommand;
- (void)sendOpenFastConnectorCommandWithIsOpen:(BOOL)isOpen;
- (void)sendOpenSlowConnectorCommandWithIsOpen:(BOOL)isOpen;
- (void)sendQuickCoolCommandWithIsOpen:(BOOL)isOpen;
- (void)sendQuickWarmCommandWithIsOpen:(BOOL)isOpen;
- (void)sendTemporaryLockCommand;
- (void)sendTrunkCommandWithIsLock:(BOOL)isLock;//后备箱操作

//双通道闭锁
//蓝牙通道，带回调
- (void)sendDuoChannelLockCommandWithCallback:(void (^)(NSString *token))callback;
- (void)sendDuoChannelPollingLockCommandWithCallback:(void (^)(NSString *token))callback;
//MQTT，带鉴权Token
- (void)sendDuoChannelLockCommandWithToken:(NSString *)token;

//剪刀门事件
- (void)sendMainDoorOpenCommand;
- (void)sendMainDoorCloseCommand;
- (void)sendSubDoorOpenCommand;
- (void)sendSubDoorCloseCommand;

- (void)sendFlashLightCommand;
- (void)sendWhistleCommand;

- (void)sendBleLocationInfo:(BOOL)isRevertLock;

// 侧滑门事件
- (void)sendLeftSlideDoorCommandWithIsOpen:(BOOL)isOpen;
- (void)sendRightSlideDoorCommandWithIsOpen:(BOOL)isOpen;

@end

#endif /* JRCarControlCellProtocol_h */

