@interface XPBLEKeyManager : NSObject
/* --------------------以下这些都是HTTP请求-------------------- */ //分享钥匙卡,可以独立调用
@property (nonatomic,strong,readonly) RACCommand* requestDestroyCardInThisDeviceCommand;

/**
生成华米手表钥匙操作的TOKEN
@param cardNo 非创建的时候传. 可选
@param vin 车辆VIN码. 必选
@param uid 用户ID. 必选
@param nickName 昵称. 可选
@param shareFrom 分享者. 可选
@param validTime 过期时间 分. 可选
@param effectiveTime 生效时间 分 TODO 预留字段, 现版本不生效. 可选
@param opType 操作类型 新增，删除，锁定. 可选
*/
@property (nonatomic,strong,readonly) RACCommand* generateTokenForHuamiCommand;//生成华米手表钥匙操作的TOKEN
@property (nonatomic,strong,readonly) RACCommand* generateTokenCommand;

@property (nonatomic,strong,readonly) RACCommand* requestDestoryBLEKeyCommand; //不能独立调用，会由destoryBLEKeyCommand内部调用
/* --------------------以上这些都是HTTP请求-------------------- */

/* --------------------以下这些都有一砂SDK参与-------------------- */
