@property (nonatomic,strong,readonly) RACCommand* verifyCommand; //认证命令（解锁认证，上锁认证，蓝牙泊车认证）
/* --------------------以上这些都有一砂SDK参与-------------------- */

@property (nonatomic, assign) BOOL connectNeedDisconnect;

