//
//  CarControlManager.h
//  XiaoPengQiChe
//
//  Created by sunxiaobo on 2018/9/15.
//  Copyright © 2018年 xiaopeng.com. All rights reserved.
//  本模块用于处理体验模式和真实模式，如果没有体验模式，则远程车控可以不通过本模块调用

#import <Foundation/Foundation.h>
#import "MQTTPublisher.h"
#import "CarControlStyleDefine.h"

@class XPCarClockOperateInfo;

@interface CarControlManager : NSObject

+ (instancetype _Nonnull )instance;


/**
 退出体验模式, 销毁体验模式的数据
 */
+ (void)eixteExperienceMode;

/**
 下拉刷新

 @param style 车控体验模式或真实车控模式
 @param successCallbackBlock 成功的回调，2.0车使用
 @param failBlock 失败的回调，2.0车使用
 @param timeoutBlock 超时的回调，2.0车使用
 */
- (void)sendForceUploadCarStateInfoRequestMessageIfNeedWithStyle:(CarControlStyle)style
                                                    successBlock:(MQTTSuccessCallbackBlock _Nullable )successCallbackBlock
                                                       failBlock:(MQTTFailCallbackBlock _Nullable )failBlock
                                                    timeoutBlock:(MQTTTimeoutCallbackBlock _Nullable )timeoutBlock;


/**
 空调控制

 @param isOpen 开或关
 @param style 车控体验模式或真实车控模式
 @param successCallbackBlock 成功的回调，2.0车使用
 @param failBlock 失败的回调，2.0车使用
 @param timeoutBlock 超时的回调，2.0车使用
 */
- (void)openAirConditioner:(BOOL)isOpen
                     style:(CarControlStyle)style
              successBlock:(MQTTSuccessCallbackBlock _Nullable )successCallbackBlock
                 failBlock:(MQTTFailCallbackBlock _Nullable )failBlock
              timeoutBlock:(MQTTTimeoutCallbackBlock _Nullable )timeoutBlock;


/**
开启空调除霜控制

@param isOpen 开或关
@param style 车控体验模式或真实车控模式
@param successCallbackBlock 成功的回调，2.0车使用
@param failBlock 失败的回调，2.0车使用
@param timeoutBlock 超时的回调，2.0车使用
*/
- (void)openAirDefrost:(BOOL)isOpen
                 style:(CarControlStyle)style
          successBlock:(MQTTSuccessCallbackBlock)successCallbackBlock
             failBlock:(MQTTFailCallbackBlock)failBlock
          timeoutBlock:(MQTTTimeoutCallbackBlock)timeoutBlock;

/**
 开启空调极速升温控制

 @param isOpen 开或关
 @param style 车控体验模式或真实车控模式
 @param successCallbackBlock 成功的回调，2.0车使用
 @param failBlock 失败的回调，2.0车使用
 @param timeoutBlock 超时的回调，2.0车使用
 */
- (void)openAirKillVirus:(BOOL)isOpen
                   style:(CarControlStyle)style
            successBlock:(MQTTSuccessCallbackBlock)successCallbackBlock
               failBlock:(MQTTFailCallbackBlock)failBlock
            timeoutBlock:(MQTTTimeoutCallbackBlock)timeoutBlock;

/**
 开启空调清洁控制

 @param isOpen 开或关
 @param style 车控体验模式或真实车控模式
 @param successCallbackBlock 成功的回调，2.0车使用
 @param failBlock 失败的回调，2.0车使用
 @param timeoutBlock 超时的回调，2.0车使用
 */
- (void)openAirClean:(BOOL)isOpen
               style:(CarControlStyle)style
        successBlock:(MQTTSuccessCallbackBlock)successCallbackBlock
           failBlock:(MQTTFailCallbackBlock)failBlock
        timeoutBlock:(MQTTTimeoutCallbackBlock)timeoutBlock;

/**
 开启空调极速升温控制

 @param isOpen 开或关
 @param style 车控体验模式或真实车控模式
 @param successCallbackBlock 成功的回调，2.0车使用
 @param failBlock 失败的回调，2.0车使用
 @param timeoutBlock 超时的回调，2.0车使用
 */
- (void)openAirKillVirus:(BOOL)isOpen
                   style:(CarControlStyle)style
            successBlock:(MQTTSuccessCallbackBlock)successCallbackBlock
               failBlock:(MQTTFailCallbackBlock)failBlock
            timeoutBlock:(MQTTTimeoutCallbackBlock)timeoutBlock;


/**
 开启空调极速升温控制

 @param isOpen 开或关
 @param style 车控体验模式或真实车控模式
 @param successCallbackBlock 成功的回调，2.0车使用
 @param failBlock 失败的回调，2.0车使用
 @param timeoutBlock 超时的回调，2.0车使用
 */
- (void)openAirHeatUp:(BOOL)isOpen
                style:(CarControlStyle)style
         successBlock:(MQTTSuccessCallbackBlock)successCallbackBlock
            failBlock:(MQTTFailCallbackBlock)failBlock
         timeoutBlock:(MQTTTimeoutCallbackBlock)timeoutBlock;

/**
 开启空调极速降温控制

 @param isOpen 开或关
 @param style 车控体验模式或真实车控模式
 @param successCallbackBlock 成功的回调，2.0车使用
 @param failBlock 失败的回调，2.0车使用
 @param timeoutBlock 超时的回调，2.0车使用
 */
- (void)openAirHeatDown:(BOOL)isOpen
                  style:(CarControlStyle)style
           successBlock:(MQTTSuccessCallbackBlock)successCallbackBlock
              failBlock:(MQTTFailCallbackBlock)failBlock
           timeoutBlock:(MQTTTimeoutCallbackBlock)timeoutBlock;



/**
 调整温度

 @param temperature 温度值
 @param style 车控体验模式或真实车控模式
 @param successCallbackBlock 成功的回调，2.0车使用
 @param failBlock 失败的回调，2.0车使用
 @param timeoutBlock 超时的回调，2.0车使用
 */
- (void)adjustAirConditionerTemperature:(int)temperature
                                  style:(CarControlStyle)style
                           successBlock:(MQTTSuccessCallbackBlock _Nullable )successCallbackBlock
                              failBlock:(MQTTFailCallbackBlock _Nullable )failBlock
                           timeoutBlock:(MQTTTimeoutCallbackBlock _Nullable )timeoutBlock;

/**
 调整风量大小

 @param volume 风量值
 @param style 车控体验模式或真实车控模式
 @param successCallbackBlock 成功的回调，2.0车使用
 @param failBlock 失败的回调，2.0车使用
 @param timeoutBlock 超时的回调，2.0车使用
 */
- (void)adjustAirConditionerVolume:(int)volume
                             style:(CarControlStyle)style
                      successBlock:(MQTTSuccessCallbackBlock _Nullable )successCallbackBlock
                         failBlock:(MQTTFailCallbackBlock _Nullable )failBlock
                      timeoutBlock:(MQTTTimeoutCallbackBlock _Nullable )timeoutBlock;


/**
 车锁控制

 @param isLock 锁或开锁
 @param style 车控体验模式或真实车控模式
 @param successCallbackBlock 成功的回调，2.0车使用
 @param failBlock 失败的回调，2.0车使用
 @param timeoutBlock 超时的回调，2.0车使用
 @retun message id
 */
- (NSString *_Nullable)lockDoor:(BOOL)isLock
                 style:(CarControlStyle)style
                   successBlock:(MQTTSuccessCallbackBlock _Nullable )successCallbackBlock
                      failBlock:(MQTTFailCallbackBlock _Nullable )failBlock
                   timeoutBlock:(MQTTTimeoutCallbackBlock _Nullable )timeoutBlock;

/**
 车锁控制

 @param isLock 锁或开锁
 @param style 车控体验模式或真实车控模式
 @param successCallbackBlock 成功的回调，2.0车使用
 @param failBlock 失败的回调，2.0车使用
 @param timeoutBlock 超时的回调，2.0车使用
 @param timeout 超时时间
 @retun message id
 */
- (NSString *_Nullable)lockDoor:(BOOL)isLock
                          style:(CarControlStyle)style
                   successBlock:(MQTTSuccessCallbackBlock _Nullable )successCallbackBlock
                      failBlock:(MQTTFailCallbackBlock _Nullable )failBlock
                   timeoutBlock:(MQTTTimeoutCallbackBlock _Nullable )timeoutBlock
                        timeout:(int)timeout;



/**
 关车窗

 @param style 车控体验模式或真实车控模式
 @param successCallbackBlock 成功的回调，2.0车使用
 @param failBlock 失败的回调，2.0车使用
 @param timeoutBlock 超时的回调，2.0车使用
 */
- (void)closeWindowWithStyle:(CarControlStyle)style
                successBlock:(MQTTSuccessCallbackBlock _Nullable )successCallbackBlock
                   failBlock:(MQTTFailCallbackBlock _Nullable )failBlock
                timeoutBlock:(MQTTTimeoutCallbackBlock _Nullable )timeoutBlock;

/**
 一键通风

