#import <Foundation/Foundation.h>

typedef void(^LocalCarInfoSuccessBlock)(void);

@class MyCarInfo;
@class WarrantCarDriverInfo;
@class CarWarrantInfo;
@class XPCarBleInfo;
NS_ASSUME_NONNULL_BEGIN

@interface CarPermissionManager : NSObject
/**
 当前用户的所有车辆信息，如果当前没有登录，则该Array的count为0
 */
@property (nonatomic, strong, readonly) NSArray<MyCarInfo*>* myCarInfos;

@property (nonatomic, copy) LocalCarInfoSuccessBlock localCarInfoSuccessBlock;

+ (instancetype)shareInstance;

- (void)sdk_setup;

/**
 清理当前用户的所以carinfo
 */
- (void)clearCarInfos;
/**
 凭VIN码找MyCarInfo
*/
- (MyCarInfo* _Nullable)carInfoForVin:(NSString* _Nonnull)vin;
/**
 当前用户的主车信息
 @return 1.如果当前没有登录，则返回nil; 2.如果当前用户名下没有车辆，则返回nil; 3.如果当前用户
          只有1辆车，则返回第一辆车；4.否则返回选定车辆
 */
- (MyCarInfo* _Nullable)defaultCarInfo;
/**
 当前用户的主车信息
 @return 1.如果当前没有登录，则返回nil; 2.如果当前用户名下没有车辆，则返回nil; 3.如果当前用户
         只有1辆车，则返回第一辆车的VIN；4.否则返回选定车辆的VIN
 */
- (NSString* _Nullable)defaultCarVin;
/**
  车辆切换信号，发送后会立即发送 XPVehicleNotificationVehicleSwitched 广播消息
  用户更新后选定主车信息后的信号
   @return 返回当前用户更新后选定主车信息后的信号。
           1.如果当前没有登录，则信号的订阅值为nil；
           2.如果当前用户名下没有车辆，则信号的订阅值为nil;
           3.如果当前用户只有1辆车，则信号的订阅值为第一辆车；
           4.否则信号的订阅值为选丁车辆

   该信号会暂存最后一次选定的车辆信息
 */
- (RACSignal<MyCarInfo*>* _Nonnull)defaultCarSwitchedSignal;
/**
 刷新车辆信息
 @return 返回刷新我的车辆信息的信号
 */
- (RACSignal<NSArray<MyCarInfo*>*>*)refreshMyCarInfos;
/**
 选定主车，该方法会引发defaultCarSwitchedSignal信号
 @param carInfo MyCarInfo* 主车信息
 */
- (void)pickCarInfoAsDefaultCarInfo:(MyCarInfo* _Nonnull)carInfo;
/**
 获取在vin=@{vin}的车辆上登录的用户信息
 */
- (RACSignal* _Nonnull)fetchAuthorizedDriverListWithVin:(NSString* _Nonnull)vin
                                                 pageNo:(NSInteger)pageNo
                                               pageSize:(NSInteger)pageSize;
/**
 车主处理普通用户的授权请求，确认永久授权
 */
- (RACSignal * _Nonnull)addPermissionPermanentlyWithVin:(NSString* _Nonnull)vin uid:(uint64_t)uid;
/**
 车主处理普通用户的授权请求，确认限时授权
 */
