#import "XPCarHomePageViewController.h"
#import <XPCarControlUtils/XPCarControlUtils.h>
#import <Lottie/Lottie.h>
#import <YYImage/YYImage.h>

@interface XPCarHomePageViewController ()

@property (nonatomic, strong) UIImageView * imageView1;
@property (nonatomic, strong) UIImageView * imageView2;
@property (nonatomic, strong) UIImageView * imageView3;
@property (nonatomic, strong) LOTAnimationView *avatarAnimationView;

@end

@implementation XPCarHomePageViewController

- (void)viewDidLoad {
    [super viewDidLoad];
    // Do any additional setup after loading the view.

    self.view.backgroundColor = [UIColor colorWithRed:0.0 green:0.0 blue:1.0 alpha:0.5];

    _imageView1 = [[UIImageView alloc] init];
    _imageView1.frame = CGRectMake(20, 20, 200, 100);
    _imageView1.image = [YYImage imageNamed:@"Air_Wind_Flow_P7.webp"];

    [self.view addSubview:_imageView1];

    _imageView2 = [[UIImageView alloc] init];
    _imageView2.frame = CGRectMake(20, 220, 200, 100);
    _imageView2.image = [UIImage imageNamed:@"Images/img_msg_guard2"];

    [self.view addSubview:_imageView2];

    _imageView3 = [[UIImageView alloc] init];
    _imageView3.frame = CGRectMake(20, 380, 200, 100);
    _imageView3.image = [UIImage imageNamed:@"Norway"];

    [self.view addSubview:_imageView3];

    self.avatarAnimationView = ({
//        LOTAnimationView *animationView = [LOTAnimationView animationNamed:@"ParkIN-TR-A.json"];
//        LOTAnimationView *animationView = [LOTAnimationView animationNamed:@"Lottie/AutoParking/parkingJson/ParkOUT-T-B.json" inBundle:XPCarResBundle];
//        NSString * path = [XPCarResBundle pathForResource:@"ParkOUT-T-B.json" ofType:nil inDirectory:@"Lottie/AutoParking/parkingJson"];
//        LOTAnimationView *animationView = [LOTAnimationView animationWithFilePath:path];
//        LOTAnimationView *animationView = [LOTAnimationView animationNamed:@"ParkIN-TR-A.json" inBundle:NSBundle.mainBundle];
        LOTAnimationView *animationView = [LOTAnimationView sdk_animationNamed:@"ParkOUT-T-B.json" inDirectory:@"Lottie/AutoParking/parkingJson"];
        animationView.loopAnimation = YES;
        animationView;
    });

    [self.view addSubview:_avatarAnimationView];
    [self.avatarAnimationView play];
}

- (void)touchesBegan:(NSSet<UITouch *> *)touches withEvent:(UIEvent *)event {
    UITouch *touch = [touches anyObject];
    if (2 == touch.tapCount) {
        [self.view removeFromSuperview];
    }
}

@end

