typedef NS_ENUM(NSUInteger, XPAPIRequestMethod) {
    XPAPIRequestMethodPOST,
    XPAPIRequestMethodGET,
    XPAPIRequestMethodDelete,
    XPAPIRequestMethodPut,
    XPAPIRequestMethodMultipartPost,

};

typedef NS_ENUM(NSUInteger, XPAPIEncryption) {
    XPAPIEncryptionNone,
    XPAPIEncryptionTee = 2,
};

typedef NS_ENUM(NSUInteger, XPAPISSLPinningMode) {
    XPAPISSLPinningModeNone,
    XPAPISSLPinningModePublicKey,
    XPAPISSLPinningModeCertificate,
};

@class XPAPIRequest;

typedef void (^XPAPIRequestCompletion) (Response *response);
typedef void (^XPAPIRequestSuccess) (id _Nullable  data, Response * _Nullable response);
typedef void (^XPAPIRequestFailure) (NSInteger httpCode, NSError * _Nullable error, Response * _Nullable response);

@interface XPAPI : NSObject

/// 获取请求对象
@property (nonatomic, strong, readonly, class) XPAPIRequest *request;

@end

/// 请求对象类
@interface XPAPIRequest : NSObject

/// 请求任务
@property (nonatomic, strong, readonly) NSURLSessionTask *task;

/// 设置请求域名, 默认取: @b XPAPIRequestManagerParams.defaultDomainInApiRequestManager
@property (nonatomic, copy, readonly) XPAPIRequest *(^domain)(NSString *domain);

/// 设置请求路径
@property (nonatomic, copy, readonly) XPAPIRequest *(^path)(NSString *path);

/// 设置请求方法, 默认: @b XPAPIRequestMethodPOST
@property (nonatomic, copy, readonly) XPAPIRequest *(^method)(XPAPIRequestMethod method);

/// 设置查询参数, 将会拼接在 url 上面
@property (nonatomic, copy, readonly) XPAPIRequest *(^query)(NSDictionary *query);

/// 设置请求头参数(不加入到签名信息中)
@property (nonatomic, copy, readonly) XPAPIRequest *(^headers)(NSDictionary *headers);
/// 设置请求头参数(加入到签名信息中)
@property (nonatomic, copy, readonly) XPAPIRequest *(^customHeaders)(NSDictionary *customHeaders);

/// 设置请求负载, 将会主在 @b HTTP 请求体中
@property (nonatomic, copy, readonly) XPAPIRequest *(^payload)(NSDictionary *payload);

/// 设置请求加密方式, 默认取 @b XPAPIRequestManagerParams.encryptionType
@property (nonatomic, copy, readonly) XPAPIRequest *(^encryption)(XPAPIEncryption encryption);

/// 设置是否允许非法证书, 默认: @b YES
//@property (nonatomic, copy, readonly) XPAPIRequest *(^allowInvalidCertificates)(BOOL allowInvalidCertificates);

/// 设置 SSL pinning 模式, 默认: @b XPAPISSLPinningModeCertificate
//@property (nonatomic, copy, readonly) XPAPIRequest *(^pinningMode)(XPAPISSLPinningMode pinningMode);

/// 设置请求是否需要携带 @b token, 默认: 当 @b encryption 设置为 @b XPAPIEncryptionTee 时, 默认为 @b YES, 当 @b encryption 设置为 @b XPAPIEncryptionNone 时, 默认为 @b NO
@property (nonatomic, copy, readonly) XPAPIRequest *(^needToken)(BOOL needToken);

/// 设置请求是否需要携带加密的头部信息, 默认: 当 @b encryption 设置为 @b XPAPIEncryptionTee 时, 默认为 @b YES, 当 @b encryption 设置为 @b XPAPIEncryptionNone 时, 默认为 @b NO
@property (nonatomic, copy, readonly) XPAPIRequest *(^needAuthorizationHeaderEncypted)(BOOL needAuthorizationHeaderEncypted);

/// 设置请求回调队列, 默认: @b dispatch_get_main_queue()
@property (nonatomic, copy, readonly) XPAPIRequest * (^subscribeOn)(dispatch_queue_t queue);

/// 设置进度回调
@property (nonatomic, copy, readonly) XPAPIRequest * (^progress)(void (^)(NSProgress *progress));

/// 设置完成回调
@property (nonatomic, copy, readonly) XPAPIRequest * (^subscribe)(XPAPIRequestCompletion completion);

/// 设置完成回调
@property (nonatomic, copy, readonly) XPAPIRequest * (^subscribeDisperse)(XPAPIRequestSuccess success, XPAPIRequestFailure failure);

/// 取消当前请求
@property (nonatomic, copy, readonly) void (^cancel)(void);

@end

NS_ASSUME_NONNULL_END

