#import <Foundation/Foundation.h>

#import <AFNetworking/AFSecurityPolicy.h>

/**
 *  Http请求方式
 */
typedef NS_ENUM(NSInteger, HttpRequestType) {

    /**
     *  Post方式
     */
    HttpRequestTypePost,
    /**
     *  Get方式
     */
    HttpRequestTypeGet,
    /**
     *  Delete方式
     */
    HttpRequestTypeDelete,
    /**
     *  Put方式
     */
    HttpRequestTypePut,
    /**
     *  MultipartPost方式
     */
    HttpRequestTypeMultipartPost,

};


/**
 Http Body传参方式
 */
typedef NS_ENUM(NSInteger, HttpRequestBodyType) {
    /**
     *  form-data方式
     */
    HttpRequestBodyTypeFormData,
};

/**
 HttpRequest请求参校验结果
 */
typedef NS_ENUM(NSInteger, HttpRequestDataVerifyResult) {
    /**
     *  未校验
     */
    HttpRequestDataVerifyResultNone,
    /**
     *  缺少Path
     */
    HttpRequestDataVerifyResultNilPath,
    /**
     *  文件上传时缺少数据
     */
    HttpRequestDataVerifyResultFormDataEmptyData,
    /**
     *  文件上传时缺少文件名
     */
    HttpRequestDataVerifyResultFormDataEmptyFileName,
    /**
     *  文件上传时缺少名称
     */
    HttpRequestDataVerifyResultFormDataEmptyName,
    /**
     *  文件上传时缺少mimeType类型
     */
    HttpRequestDataVerifyResultFormDataEmptyMimeType,
    /**
     *  文件上传时必须是要异步
     */
    HttpRequestDataVerifyResultFormDataIsNotAsync,
    /**
     *  下载文件时缺少下载url
     */
    HttpRequestDataVerifyResultFormDataIsErrorDownloadUrl,
    /**
     *  下载文件时缺少保存路径
     */
    HttpRequestDataVerifyResultFormDataIsEmptySavePath,
    /**
     *  校验成功
     */
    HttpRequestDataVerifyResultSuccess,
};

/**
 HttpRequest加密方式
 */
typedef NS_ENUM(NSInteger, HttpRequestEncryptionType) {
    //无加密
    HttpRequestEncryptionTypeNone,
    //爱迪徳加密
    HttpRequestEncryptionTypeIrdeto,
    //tee加密
    HttpRequestEncryptionTypeTee,
    // oqs 后量子加密
    HttpRequestEncryptionTypeOQS,

    //预留加密方式
    HttpRequestEncryptionTypeOther,
};

@interface HttpRequestModel : NSObject

@property (nonatomic, assign, readonly) HttpRequestType requestType;
@property (nonatomic, assign, readonly) HttpRequestBodyType bodyType;
@property (nonatomic, strong, readonly) NSString * _Nonnull path;
@property (nonatomic, strong, readonly) NSDictionary * _Nullable bodyParams;
@property (nonatomic, strong, readonly) NSDictionary * _Nullable pathParams;
@property (nonatomic, strong, readonly) NSDictionary * _Nonnull finalBodyParams;
@property (nonatomic, assign, readonly) HttpRequestDataVerifyResult verifyResult;
// 主域名，不传的话，默认值为 HTTPApiRequestDefaultDomain
@property (nonatomic, strong, readonly) NSString * _Nonnull envDomainURL;
// 会添加到签名
@property (nonatomic, strong, readwrite) NSDictionary<NSString *, id> * _Nullable customHeaders;
// 不会添加到签名
@property (nonatomic, strong, readwrite) NSDictionary<NSString *, id> * _Nullable additionHeaders;
/********** 上传文件时要用到的参数 **********/
// data The data to be encoded and appended to the form data
@property (nonatomic, strong, readwrite) NSData * _Nonnull formDataFileData;
// The name to be associated with the specified data. This parameter must not be `nil`.
@property (nonatomic, strong, readwrite) NSString * _Nonnull formDataFileName;
// The filename to be associated with the specified data. This parameter must not be `nil`.
@property (nonatomic, strong, readwrite) NSString * _Nonnull formDataName;
// The MIME type of the specified data. (For example, the MIME type for a JPEG image is image/jpeg.) For a list of valid MIME types, see http://www.iana.org/assignments/media-types/. This parameter must not be `nil`.
@property (nonatomic, strong, readwrite) NSString * _Nonnull formDataMimeType;


/********** 通用参数 **********/
@property (nonatomic, strong, readonly) NSString * _Nonnull accessToken;
@property (nonatomic, strong, readonly) NSString * _Nonnull refreshToken;
@property (nonatomic, assign, readwrite) BOOL isRefreshAccessToken;
@property (nonatomic, assign) HttpRequestEncryptionType encryptionType;
@property (nonatomic, assign) BOOL isNeedAuthorizationHeaderEncypted;//是否需要Authorization头参数：加密后的数据
@property (nonatomic, assign) BOOL isNeedToken;//是否需要Token：登录时服务端返回的token数据
@property (nonatomic, strong) NSDictionary<NSString *, id >*headerFields; // 经过处理后的请求头参数, 不允许外部设置

@property (nonatomic, assign, readwrite) BOOL allowInvalidCertificates DEPRECATED_MSG_ATTRIBUTE("This attribute has been deprecated, please config in XPNetwork.box"); //是否验证本地证书域名，默认值为YES
@property (nonatomic, assign, readwrite) AFSSLPinningMode pinningMode DEPRECATED_MSG_ATTRIBUTE("This attribute has been deprecated, please config in XPNetwork.box"); //证书验证模式, 默认值为AFSSLPinningModeCertificate


/********** 其它 **********/
@property (nonatomic, assign, readonly) long long timeStamp;

/**
 返回HttpRequestModel

 @param path 请求的path
 @param pathParams path后的参数
 @param bodyParams body请求参数
 @param requestType request请求类型，HttpRequestType，默认是 HttpRequestTypePost
