#if __has_include(<XLog/LogUtil.h>) //has XLog
#import <XLog/LogUtil.h>

#define DLogError(frmt, ...)   XLOG_ERROR(@"", frmt, ##__VA_ARGS__)
#define DLoggWarn(frmt, ...)   XLOG_WARNING(@"", frmt, ##__VA_ARGS__)
#define DLogInfo(frmt, ...)    XLOG_INFO(@"", frmt, ##__VA_ARGS__)
#define DLogDebug(frmt, ...)   XLOG_DEBUG(@"", frmt, ##__VA_ARGS__)
#define DLogVerbose(frmt, ...) XLOG_VERBOSE(@"", frmt, ##__VA_ARGS__)


#define DLogError_if(exp, frmt, ...)   __IF_DO(exp, XLOG_ERROR(@"", frmt, ##__VA_ARGS__);)
#define DLoggWarn_if(exp, frmt, ...)   __IF_DO(exp, XLOG_WARNING(@"", frmt, ##__VA_ARGS__);) 
#define DLogInfo_if(exp, frmt, ...)    __IF_DO(exp, XLOG_INFO(@"", frmt, ##__VA_ARGS__);) 
#define DLogDebug_if(exp, frmt, ...)   __IF_DO(exp, XLOG_DEBUG(@"", frmt, ##__VA_ARGS__);)
#define DLogVerbose_if(exp, frmt, ...) __IF_DO(exp, XLOG_VERBOSE(@"", frmt, ##__VA_ARGS__);)

//带Tag的日志宏
#define DLogTagError(__tag__, frmt, ...)   XLOG_ERROR(__tag__, frmt, ##__VA_ARGS__)
#define DLogTagWarn(__tag__, frmt, ...)    XLOG_WARNING(__tag__, frmt, ##__VA_ARGS__)
#define DLogTagInfo(__tag__, frmt, ...)    XLOG_INFO(__tag__, frmt, ##__VA_ARGS__)
#define DLogTagDebug(__tag__, frmt, ...)   XLOG_DEBUG(__tag__, frmt, ##__VA_ARGS__)
#define DLogTagVerbose(__tag__, frmt, ...) XLOG_VERBOSE(__tag__, frmt, ##__VA_ARGS__)

#define DLogTagError_if(exp,__tag__, frmt, ...)   __IF_DO(exp, XLOG_ERROR(__tag__, frmt, ##__VA_ARGS__);)
#define DLogTagWarn_if(exp,__tag__, frmt, ...)    __IF_DO(exp, XLOG_WARNING(__tag__, frmt, ##__VA_ARGS__);)
#define DLogTagInfo_if(exp,__tag__, frmt, ...)    __IF_DO(exp, XLOG_INFO(__tag__, frmt, ##__VA_ARGS__);) 
#define DLogTagDebug_if(exp,__tag__, frmt, ...)   __IF_DO(exp, XLOG_DEBUG(__tag__, frmt, ##__VA_ARGS__);)
#define DLogTagVerbose_if(exp,__tag__, frmt, ...) __IF_DO(exp, XLOG_VERBOSE(__tag__, frmt, ##__VA_ARGS__);) 

#define DLogClassAssert(condition, description, ...) \
do { \
    if (!(condition)) { \
        XLOG_ERROR(@"", description, ##__VA_ARGS__); \
    }\
    assert(condition); \
} while(0);

#else //has no XLog

#define DLogError(frmt, ...)   NSLog(frmt, ##__VA_ARGS__)
#define DLoggWarn(frmt, ...)   NSLog(frmt, ##__VA_ARGS__)
#define DLogInfo(frmt, ...)    NSLog(frmt, ##__VA_ARGS__)
#define DLogDebug(frmt, ...)   NSLog(frmt, ##__VA_ARGS__)
#define DLogVerbose(frmt, ...) NSLog(frmt, ##__VA_ARGS__)

#define DLogError_if(exp,frmt, ...)   if ((exp)) { NSLog(frmt, ##__VA_ARGS__); }

#define DLoggWarn_if(exp,frmt, ...)   if ((exp)) { NSLog(frmt, ##__VA_ARGS__); }
#define DLogInfo_if(exp,frmt, ...)    if ((exp)) { NSLog(frmt, ##__VA_ARGS__); }
#define DLogDebug_if(exp,frmt, ...)   if ((exp)) { NSLog(frmt, ##__VA_ARGS__); }
#define DLogVerbose_if(exp,frmt, ...) if ((exp)) { NSLog(frmt, ##__VA_ARGS__); }


//带Tag的日志宏
#define DLogTagError(__tag__, frmt, ...)   \
do {\
    @autoreleasepool { \
        NSString* aMessage = [NSString stringWithFormat:@"【%@】%@", __tag__, [NSString stringWithFormat:frmt, ##__VA_ARGS__, nil]]; \
        NSLog(@"%@", aMessage);\
    } \
} while(0);\

#define DLogTagWarn(__tag__, frmt, ...)    \
do {\
    @autoreleasepool { \
        NSString* aMessage = [NSString stringWithFormat:@"【%@】%@", __tag__, [NSString stringWithFormat:frmt, ##__VA_ARGS__, nil]]; \
        NSLog(@"%@", aMessage);\
    } \
