//
//  XPAppSettings.h
//  XiaoPengQiChe
//
//   OTAConfig 替代品，App配置，走OCM平台，提供ABTest以及灰度能力
//   后台可以限定uid和vin下发不同的配置参数，也可以限定一定百分比的用户下发指定的参数
//    App 在收到切车事件时(含启动)，调用一次在线拉取数据方法，内部重试3次联网
//    提供配置项数据变更监听接口，可监听指定配置项数据变更，也可以监听刷新成功事件
//
//  Created by yangcy on 2025/05/15.
//  Copyright © 2025 xiaopeng.com. All rights reserved.
//

#import <Foundation/Foundation.h>

NS_ASSUME_NONNULL_BEGIN

@interface XPAppSettings : NSObject

// 登录后调用
+ (void)enterAccount:(uint64_t)uid;

// 清除所有本地缓存数据，当退出登录时调用，不发送数据变更通知
+ (void)deleteAllSettings;

// 联网请求数据，切车后调用（含App启动）
// code: 0 - 成功
+ (void)requestSettings:(NSString *)vin vehicleTypeCode:(NSString *)vehicleTypeCode vehicleTypeName:(NSString *)vehicleTypeName callback:(void(^ _Nullable)(int code))callback;

#pragma mark - 配置项数据读取
+ (NSString * _Nullable)stringForKey:(NSString *)key vin:(NSString *)vin;
+ (BOOL)boolForKey:(NSString *)key vin:(NSString *)vin;
+ (int32_t)int32ForKey:(NSString *)key vin:(NSString *)vin;
+ (int64_t)int64ForKey:(NSString *)key vin:(NSString *)vin;
+ (double)doubleForKey:(NSString *)key vin:(NSString *)vin;
+ (NSDictionary * _Nullable)dictionaryForKey:(NSString *)key vin:(NSString *)vin; // OCM 后台配置为 Json String，自动解析为字典，解析失败则返回 nil
+ (NSArray * _Nullable)arrayForKey:(NSString *)key vin:(NSString *)vin; // OCM 后台配置为 Json String，自动解析为数组，解析失败则返回 nil

#pragma mark - 配置数据变更监听
// 数据变更监听，建立监听后，联网刷新导致Value变化，就会发出通知
// 如果是Bool或Number，假如之前没有数据，收到下发数据为 false 或 0，也会发出通知
+ (void)addDataChangedObserver:(void(^)(NSString *key, NSString *vin))block forKey:(NSString *)key vin:(NSString *)vin; // 切车后需要重新建立监听，不推荐

// 推荐的监听方式，所有车配置变化都会通知，需要业务层检测vin
+ (void)addDataChangedObserver:(void(^)(NSString *key, NSString *vin))block forKey:(NSString *)key;

+ (void)removeDataChangedObserver:(void(^)(NSString *key, NSString *vin))block;
// 正常使用无法移除监听，实在需要的话，则自行使用变量来记录 block，然后调用移除方法

// 监听整个配置数据刷新通知，成功请求到在线数据则发出通知
// 所有车辆刷新都会通知，业务方自行过滤不需要的vin
+ (void)addRefreshedObserver:(void(^)(NSString *vin))block;

+ (void)removeRefreshedObserver:(void(^)(NSString *vin))block;

@end

NS_ASSUME_NONNULL_END
